type Listener = (...args: unknown[]) => void;

interface ListenerEntry {
  original: Listener;
  wrapper: Listener;
}

export class EventEmitter {
  private listeners = new Map<string, ListenerEntry[]>();

  // Register listener, return unsubscribe function
  on(event: string, listener: Listener): () => void {
    const entry: ListenerEntry = { original: listener, wrapper: listener };
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)!.push(entry);
    return () => this.off(event, listener);
  }

  // Listener fires only once
  once(event: string, listener: Listener): void {
    const wrapper: Listener = (...args: unknown[]) => {
      this.off(event, listener);
      listener(...args);
    };
    const entry: ListenerEntry = { original: listener, wrapper };
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)!.push(entry);
  }

  // Call all listeners, return true if any existed
  emit(event: string, ...args: unknown[]): boolean {
    const entries = this.listeners.get(event);
    if (!entries || entries.length === 0) {
      return false;
    }
    // Snapshot before iterating to handle mid-emit removals gracefully
    const snapshot = [...entries];
    for (const entry of snapshot) {
      entry.wrapper(...args);
    }
    return true;
  }

  // Remove specific listener (matched by original reference)
  off(event: string, listener: Listener): void {
    const entries = this.listeners.get(event);
    if (!entries) return;
    const index = entries.findIndex((e) => e.original === listener);
    if (index !== -1) {
      entries.splice(index, 1);
    }
    // Clean up empty event keys
    if (entries.length === 0) {
      this.listeners.delete(event);
    }
  }

  // Remove all listeners, optionally scoped to one event
  removeAllListeners(event?: string): void {
    if (event === undefined) {
      this.listeners.clear();
    } else {
      this.listeners.delete(event);
    }
  }

  // Return count of listeners for an event
  listenerCount(event: string): number {
    return this.listeners.get(event)?.length ?? 0;
  }

  // Return array of event names that have active listeners
  eventNames(): string[] {
    return [...this.listeners.keys()];
  }
}

